function Products(e){{var t=this;e.history}this.getScrollInterval=function(){var e=$(document).width();return 500>e?"150px":"336px"},this.loadOnReady=function(){$(".horizon-prev").click(function(){event.preventDefault(),$(this).closest(".scroll-scope").find(".ul-panel").stop().animate({scrollLeft:"-="+t.getScrollInterval()},"slow")}),$(".horizon-next").click(function(){event.preventDefault(),$(this).closest(".scroll-scope").find(".ul-panel").stop().animate({scrollLeft:"+="+t.getScrollInterval()},"slow")}),$(".btn-fav").on("click",function(){var t=$(this).attr("relkey"),a=$(this);$.ajax({type:"POST",url:"/ajax-item.php",data:"action=updateFavoritProduct&itemkey="+t,success:function(){a.toggleClass("text-red-cardinal")}})})}}